import * as path from 'path';
import * as fs from 'fs';
import * as os from 'os';
import { Dirty } from '../../../../../../../../../../../subject_repositories/node-dirty/lib/dirty/dirty.js';

describe('Dirty drain event after backpressure with empty queue', () => {
  it('should emit drain after write stream drains when queue is empty and _waitForDrain was set', (done) => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'dirty-drain-test-'));
    const dbPath = path.join(tmpDir, 'test.db');

    const db = new Dirty(dbPath);

    db.on('load', () => {
      db.on('error', (err: Error) => {
        done(err);
      });

      // Write many large records at once to force backpressure (_waitForDrain = true)
      // Then wait for drain to be emitted
      const largeValue = 'x'.repeat(128 * 1024); // 128KB per record
      const numWrites = 30;
      let cbCount = 0;

      const onDrain = () => {
        try {
          fs.rmSync(tmpDir, { recursive: true });
        } catch (e) {
          // ignore
        }
        done();
      };

      db.once('drain', onDrain);

      for (let i = 0; i < numWrites; i++) {
        db.set(`key${i}`, { data: largeValue });
      }
    });

    db.on('error', (err: Error) => {
      done(err);
    });
  }, 15000);
});
